+    let mut line = 0usize;
+    while out.len() < size {
+        out.extend_from_slice(LINE_PREFIX);
+        if line % 64 == 0 {
+            out.extend_from_slice(ANSI_WARN);
+        }
+        out.extend_from_slice(BODY);
+        out.push(b'\n');
+        line += 1;
+    }
+    out.truncate(size);
